const ordersRaw = $('Fetch Orders Supabase').first().json;
const allOrders = Array.isArray(ordersRaw) ? ordersRaw : [ordersRaw].filter(Boolean);
const contractorsRaw = $('Fetch Contractors Supabase').first().json;
const allContractors = Array.isArray(contractorsRaw) ? contractorsRaw : [contractorsRaw].filter(Boolean);

// Сегодняшняя дата (MSK = UTC+3)
const now = new Date();
const mskOffset = 3 * 60 * 60 * 1000;
const mskNow = new Date(now.getTime() + mskOffset);
const todayStr = mskNow.toISOString().slice(0, 10); // YYYY-MM-DD

// Фильтруем заказы за сегодня
const todayOrders = allOrders.filter(o => {
  if (!o.created_at) return false;
  const orderDate = new Date(o.created_at);
  const orderMsk = new Date(orderDate.getTime() + mskOffset);
  return orderMsk.toISOString().slice(0, 10) === todayStr;
});

const total = todayOrders.length;
const newOrders = todayOrders.filter(o => o.status === 'new').length;
const priced = todayOrders.filter(o => o.status === 'priced').length;
const paid = todayOrders.filter(o => o.status === 'paid').length;
const completed = todayOrders.filter(o => o.status === 'completed').length;
const cancelled = todayOrders.filter(o => o.status === 'cancelled').length;
const revenue = todayOrders.filter(o => ['paid', 'completed', 'in_progress'].includes(o.status)).reduce((sum, o) => sum + (Number(o.platform_margin) || 0), 0);
const conversion = total > 0 ? Math.round(completed / total * 100) : 0;

// Топ исполнитель дня
const todayExecutors = todayOrders
  .filter(o => o.status === 'completed' && o.contractor_id)
  .reduce((acc, o) => {
    acc[o.contractor_id] = (acc[o.contractor_id] || 0) + 1;
    return acc;
  }, {});

let topContractor = 'нет данных';
const topEntry = Object.entries(todayExecutors)
  .sort((a, b) => b[1] - a[1])[0];

if (topEntry) {
  const c = allContractors.find(c => String(c.id) === String(topEntry[0]));
  if (c) {
    topContractor = `${c.name || 'Без имени'} (${topEntry[1]} заказов)`;
  }
}

// Общая статистика
const totalContractors = allContractors.length;
const activeContractors = allContractors.filter(c => c.status === 'active' || c.status === 'verified').length;

const dateFormatted = mskNow.toLocaleDateString('ru-RU', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

return [{
  json: {
    date: dateFormatted,
    total, newOrders, priced, paid, completed, cancelled,
    revenue, conversion,
    topContractor,
    totalContractors, activeContractors,
    totalAllOrders: allOrders.length
  }
}];

